FUNCTION check_stock(p_product_id NUMBER, p_qty NUMBER) RETURN NUMBER AS
  v_available NUMBER;
BEGIN
  SELECT stock_qty INTO v_available FROM products WHERE id = p_product_id;
  IF v_available >= p_qty THEN RETURN 1; ELSE RETURN 0; END IF;
EXCEPTION WHEN NO_DATA_FOUND THEN RETURN -1;
END;

PROCEDURE check_tier_upgrade(p_customer_id NUMBER) AS
  v_spent NUMBER(12,2);
  v_tier VARCHAR2(20);
  v_new_tier VARCHAR2(20);
  v_email VARCHAR2(255);
BEGIN
  SELECT total_spent, tier, email INTO v_spent, v_tier, v_email FROM customers WHERE id = p_customer_id;
  v_new_tier := CASE WHEN v_spent >= 10000 THEN 'vip' WHEN v_spent >= 1000 THEN 'premium' ELSE 'standard' END;
  IF v_new_tier != v_tier THEN
    UPDATE customers SET tier = v_new_tier WHERE id = p_customer_id;
    send_notification(v_email, 'tier_upgrade', 'You are now ' || UPPER(v_new_tier));
    log_activity('customer', p_customer_id, 'tier_upgrade');
  END IF;
END;

PROCEDURE confirm_order(p_order_id NUMBER) AS
  v_status VARCHAR2(20);
  v_customer_id NUMBER;
  v_email VARCHAR2(255);
  CURSOR c_items IS SELECT product_id, qty FROM order_items WHERE order_id = p_order_id;
BEGIN
  SELECT status, customer_id INTO v_status, v_customer_id FROM orders WHERE id = p_order_id;
  IF v_status != 'pending' THEN
    RAISE_APPLICATION_ERROR(-20002, 'Order not pending');
  END IF;

  FOR item IN c_items LOOP
    reserve_stock(item.product_id, item.qty);
  END LOOP;

  UPDATE orders SET status = 'confirmed' WHERE id = p_order_id;

  SELECT email INTO v_email FROM customers WHERE id = v_customer_id;
  send_notification(v_email, 'order_confirmed', 'Your order #' || p_order_id || ' is confirmed');
  log_activity('order', p_order_id, 'confirmed');
  COMMIT;
EXCEPTION
  WHEN OTHERS THEN
    ROLLBACK;
    log_activity('order', p_order_id, 'confirm_failed');
    RAISE;
END;

PROCEDURE log_activity(p_entity VARCHAR2, p_id NUMBER, p_action VARCHAR2) AS
BEGIN
  INSERT INTO audit_log (entity_type, entity_id, action) VALUES (p_entity, p_id, p_action);
END;

PROCEDURE process_payment(p_order_id NUMBER, p_method VARCHAR2) AS
  v_total NUMBER(12,2);
  v_customer_id NUMBER;
  v_email VARCHAR2(255);
BEGIN
  SELECT total, customer_id INTO v_total, v_customer_id FROM orders WHERE id = p_order_id;

  UPDATE orders SET status = 'paid' WHERE id = p_order_id;
  UPDATE customers SET total_spent = total_spent + v_total WHERE id = v_customer_id;

  check_tier_upgrade(v_customer_id);

  SELECT email INTO v_email FROM customers WHERE id = v_customer_id;
  send_notification(v_email, 'payment_received', 'Payment of $' || v_total || ' received');
  log_activity('payment', p_order_id, 'processed');
  COMMIT;
END;

PROCEDURE reserve_stock(p_product_id NUMBER, p_qty NUMBER) AS
  v_ok NUMBER;
BEGIN
  v_ok := check_stock(p_product_id, p_qty);
  IF v_ok != 1 THEN
    RAISE_APPLICATION_ERROR(-20001, 'Insufficient stock');
  END IF;
  UPDATE products SET stock_qty = stock_qty - p_qty WHERE id = p_product_id;
  log_activity('product', p_product_id, 'stock_reserved');
END;

PROCEDURE send_notification(p_email VARCHAR2, p_type VARCHAR2, p_body VARCHAR2) AS
  v_id NUMBER;
BEGIN
  INSERT INTO notifications (email, notif_type, body) VALUES (p_email, p_type, p_body) RETURNING id INTO v_id;
  log_activity('notification', v_id, 'queued');
END;

TRIGGER trg_order_status_audit
  AFTER UPDATE OF status ON orders FOR EACH ROW
BEGIN
  log_activity('order', :NEW.id, 'status_' || :NEW.status);
END;

-- ═══ Level 0: Utility SPs (called by everyone) ═══

CREATE   PROCEDURE Audit.sp_LogActivity
    @EntityType VARCHAR(50), @EntityId INT, @Action VARCHAR(50),
    @OldData NVARCHAR(MAX) = NULL, @NewData NVARCHAR(MAX) = NULL,
    @PerformedBy VARCHAR(100) = 'system'
AS
BEGIN
    SET NOCOUNT ON;
    INSERT INTO Audit.ActivityLog (EntityType, EntityId, Action, OldData, NewData, PerformedBy)
    VALUES (@EntityType, @EntityId, @Action, @OldData, @NewData, @PerformedBy);
END;

-- ═══════════════════════════════════════════════════════════
-- SP MAIN: Process Card Transaction (the big one ~30 params)
-- Calls: sp_ValidateCard, sp_ValidateBalance, sp_CheckFraud,
--        sp_SettleTransaction, sp_SendNotification, sp_LogActivity
-- ═══════════════════════════════════════════════════════════

CREATE   PROCEDURE Banking.sp_ProcessCardTransaction
    -- Input params
    @CardNumber VARCHAR(20),
    @CVV VARCHAR(4),
    @ExpiryMonth INT,
    @ExpiryYear INT,
    @Amount DECIMAL(18,2),
    @Currency VARCHAR(3),
    @MerchantName VARCHAR(200),
    @MerchantCategory VARCHAR(50),
    @TransType VARCHAR(20),          -- purchase, withdrawal, refund
    @Description VARCHAR(500) = NULL,
    @ChannelType VARCHAR(20) = 'POS', -- POS, ATM, ONLINE, MOBILE
    @TerminalId VARCHAR(50) = NULL,
    -- OUTPUT params
    @TransactionId INT OUTPUT,
    @AuthCode VARCHAR(20) OUTPUT,
    @ResponseCode VARCHAR(10) OUTPUT,
    @ResponseMessage VARCHAR(500) OUTPUT,
    @ApprovedAmount DECIMAL(18,2) OUTPUT,
    @RemainingBalance DECIMAL(18,2) OUTPUT,
    @RiskScore INT OUTPUT,
    @ProcessingTimeMs INT OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @StartTime DATETIME2 = GETDATE();
    DECLARE @CardId INT, @AccountId INT, @CardStatus VARCHAR(20), @CardType VARCHAR(20);
    DECLARE @IsCardValid BIT, @CardMsg VARCHAR(500);
    DECLARE @CurrentBalance DECIMAL(18,2), @AvailableBalance DECIMAL(18,2);
    DECLARE @DailyUsed DECIMAL(18,2), @MonthlyUsed DECIMAL(18,2);
    DECLARE @DailyLimit DECIMAL(18,2), @MonthlyLimit DECIMAL(18,2);
    DECLARE @IsBalanceOk BIT, @BalanceMsg VARCHAR(500);
    DECLARE @IsFraudFlagged BIT, @FraudDetails VARCHAR(MAX), @FraudAction VARCHAR(50);

    SET @ResponseCode = '99';
    SET @ResponseMessage = 'Processing error';
    SET @ApprovedAmount = 0;
    SET @RiskScore = 0;

    BEGIN TRY
        BEGIN TRANSACTION;

        -- ══ STEP 1: Card Validation ══
        EXEC Cards.sp_ValidateCard 
            @CardNumber, @CVV, @ExpiryMonth, @ExpiryYear,
            @CardId OUTPUT, @AccountId OUTPUT, @CardStatus OUTPUT, @CardType OUTPUT,
            @IsCardValid OUTPUT, @CardMsg OUTPUT;

        IF @IsCardValid = 0
        BEGIN
            SET @ResponseCode = '14'; -- Invalid card
            SET @ResponseMessage = @CardMsg;
            GOTO TransactionDeclined;
        END;

        -- ══ STEP 2: Balance & Limit Validation ══
        EXEC Banking.sp_ValidateBalance 
            @AccountId, @Amount, @TransType,
            @CurrentBalance OUTPUT, @AvailableBalance OUTPUT,
            @DailyUsed OUTPUT, @MonthlyUsed OUTPUT,
            @DailyLimit OUTPUT, @MonthlyLimit OUTPUT,
            @IsBalanceOk OUTPUT, @BalanceMsg OUTPUT;

        IF @IsBalanceOk = 0
        BEGIN
            SET @ResponseCode = '51'; -- Insufficient funds
            SET @ResponseMessage = @BalanceMsg;
            GOTO TransactionDeclined;
        END;

        -- ══ STEP 3: Fraud Check ══
        EXEC Fraud.sp_CheckFraud 
            @AccountId, @CardId, @Amount, @MerchantName, @MerchantCategory, @TransType,
            @RiskScore OUTPUT, @IsFraudFlagged OUTPUT, @FraudDetails OUTPUT, @FraudAction OUTPUT;

        IF @FraudAction = 'block'
        BEGIN
            SET @ResponseCode = '59'; -- Suspected fraud
            SET @ResponseMessage = 'Transaction blocked: ' + @FraudDetails;
            -- Block the card
            UPDATE Cards.Cards SET Status = 'blocked', BlockedReason = @FraudDetails WHERE Id = @CardId;
            GOTO TransactionDeclined;
        END;

        -- ══ STEP 4: Authorize & Debit ══
        SET @AuthCode = 'AUTH' + RIGHT('000000' + CAST(ABS(CHECKSUM(NEWID())) % 999999 AS VARCHAR), 6);
        SET @ApprovedAmount = @Amount;

        -- Debit the account
        UPDATE Banking.Accounts 
        SET Balance = Balance - @Amount, AvailableBalance = AvailableBalance - @Amount
        WHERE Id = @AccountId;

        -- Create transaction record
        INSERT INTO Banking.Transactions 
            (AccountId, CardId, TransType, Amount, Currency, MerchantName, MerchantCategory, Status, AuthCode, ResponseCode, ResponseMessage, RiskScore, ProcessedAt)
        VALUES 
            (@AccountId, @CardId, @TransType, @Amount, @Currency, @MerchantName, @MerchantCategory, 'approved', @AuthCode, '00', 'Approved', @RiskScore, GETDATE());
        SET @TransactionId = SCOPE_IDENTITY();

        SET @ResponseCode = '00';
        SET @ResponseMessage = 'Approved';
        SET @RemainingBalance = @AvailableBalance - @Amount;

        -- ══ STEP 5: Settlement ══
        EXEC Settlement.sp_QueueSettlement @TransactionId, @Amount, @MerchantCategory;

        -- ══ STEP 6: Notify Customer ══
        DECLARE @CustomerEmail VARCHAR(255);
        SELECT @CustomerEmail = c.Email FROM Orders.Customers c 
        JOIN Banking.Accounts a ON a.CustomerId = c.Id WHERE a.Id = @AccountId;

        IF @CustomerEmail IS NOT NULL
            EXEC Notifications.sp_SendNotification @CustomerEmail, 'transaction_approved',
                'Transaction Approved', @MerchantName;

        -- ══ STEP 7: Audit ══
        EXEC Audit.sp_LogActivity 'transaction', @TransactionId, 'approved';

        -- Fraud review notification
        IF @FraudAction = 'review'
        BEGIN
            INSERT INTO Fraud.FraudAlerts (TransactionId, AlertType, RiskScore, Details, ActionTaken)
            VALUES (@TransactionId, 'review', @RiskScore, @FraudDetails, 'pending_review');
            EXEC Notifications.sp_SendNotification 'fraud-team@company.com', 'fraud_review',
                'Transaction Review Required', @FraudDetails;
        END;

        COMMIT TRANSACTION;
        SET @ProcessingTimeMs = DATEDIFF(MILLISECOND, @StartTime, GETDATE());
        RETURN;

        TransactionDeclined:
            -- Log declined transaction
            INSERT INTO Banking.Transactions 
                (AccountId, CardId, TransType, Amount, Currency, MerchantName, MerchantCategory, Status, ResponseCode, ResponseMessage, RiskScore, ProcessedAt)
            VALUES 
                (@AccountId, @CardId, @TransType, @Amount, @Currency, @MerchantName, @MerchantCategory, 'declined', @ResponseCode, @ResponseMessage, @RiskScore, GETDATE());
            SET @TransactionId = SCOPE_IDENTITY();
            EXEC Audit.sp_LogActivity 'transaction', @TransactionId, 'declined';
            COMMIT TRANSACTION;
            SET @ProcessingTimeMs = DATEDIFF(MILLISECOND, @StartTime, GETDATE());

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;
        SET @ResponseCode = '99';
        SET @ResponseMessage = ERROR_MESSAGE();
        SET @ProcessingTimeMs = DATEDIFF(MILLISECOND, @StartTime, GETDATE());
        EXEC Audit.sp_LogActivity 'transaction', @TransactionId, 'error';
    END CATCH
END;

-- ═══════════════════════════════════════════════════════════
-- SP Level 0: Balance/Limit Validation
-- ═══════════════════════════════════════════════════════════

CREATE   PROCEDURE Banking.sp_ValidateBalance
    @AccountId INT,
    @Amount DECIMAL(18,2),
    @TransType VARCHAR(20),
    -- OUTPUT
    @CurrentBalance DECIMAL(18,2) OUTPUT,
    @AvailableBalance DECIMAL(18,2) OUTPUT,
    @DailyUsed DECIMAL(18,2) OUTPUT,
    @MonthlyUsed DECIMAL(18,2) OUTPUT,
    @DailyLimit DECIMAL(18,2) OUTPUT,
    @MonthlyLimit DECIMAL(18,2) OUTPUT,
    @IsApproved BIT OUTPUT,
    @DeclineReason VARCHAR(500) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    SET @IsApproved = 0;
    SET @DeclineReason = '';

    SELECT @CurrentBalance = Balance, @AvailableBalance = AvailableBalance,
           @DailyLimit = DailyLimit, @MonthlyLimit = MonthlyLimit
    FROM Banking.Accounts WHERE Id = @AccountId;

    -- Calculate daily/monthly usage
    SELECT @DailyUsed = ISNULL(SUM(Amount), 0) FROM Banking.Transactions 
    WHERE AccountId = @AccountId AND CAST(CreatedAt AS DATE) = CAST(GETDATE() AS DATE) AND Status = 'approved';

    SELECT @MonthlyUsed = ISNULL(SUM(Amount), 0) FROM Banking.Transactions 
    WHERE AccountId = @AccountId AND MONTH(CreatedAt) = MONTH(GETDATE()) AND YEAR(CreatedAt) = YEAR(GETDATE()) AND Status = 'approved';

    -- Check sufficient balance
    IF @AvailableBalance < @Amount
    BEGIN SET @DeclineReason = 'Insufficient funds. Available: ' + CAST(@AvailableBalance AS VARCHAR); RETURN; END;

    -- Check daily limit
    IF (@DailyUsed + @Amount) > @DailyLimit
    BEGIN SET @DeclineReason = 'Daily limit exceeded. Used: ' + CAST(@DailyUsed AS VARCHAR) + ' / Limit: ' + CAST(@DailyLimit AS VARCHAR); RETURN; END;

    -- Check monthly limit
    IF (@MonthlyUsed + @Amount) > @MonthlyLimit
    BEGIN SET @DeclineReason = 'Monthly limit exceeded'; RETURN; END;

    SET @IsApproved = 1;
    EXEC Audit.sp_LogActivity 'account', @AccountId, 'balance_validated';
END;

-- ═══════════════════════════════════════════════════════════
-- Trigger: Auto-block card on 3 consecutive declines
-- ═══════════════════════════════════════════════════════════

CREATE   TRIGGER Banking.trg_AutoBlockCard ON Banking.Transactions AFTER INSERT
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @CardId INT, @Status VARCHAR(20);
    SELECT @CardId = CardId, @Status = Status FROM inserted;

    IF @Status = 'declined' AND @CardId IS NOT NULL
    BEGIN
        DECLARE @DeclineCount INT;
        SELECT @DeclineCount = COUNT(*) FROM (
            SELECT TOP 3 Status FROM Banking.Transactions 
            WHERE CardId = @CardId ORDER BY CreatedAt DESC
        ) t WHERE Status = 'declined';

        IF @DeclineCount >= 3
        BEGIN
            UPDATE Cards.Cards SET Status = 'blocked', BlockedReason = '3 consecutive declines' WHERE Id = @CardId;
            EXEC Audit.sp_LogActivity 'card', @CardId, 'auto_blocked';
        END;
    END;
END;

-- ═══════════════════════════════════════════════════════════
-- SP Level 0: Card Validation (called by main processor)
-- ═══════════════════════════════════════════════════════════

CREATE   PROCEDURE Cards.sp_ValidateCard
    @CardNumber VARCHAR(20),
    @CVV VARCHAR(4),
    @ExpiryMonth INT,
    @ExpiryYear INT,
    -- OUTPUT params
    @CardId INT OUTPUT,
    @AccountId INT OUTPUT,
    @CardStatus VARCHAR(20) OUTPUT,
    @CardType VARCHAR(20) OUTPUT,
    @IsValid BIT OUTPUT,
    @ValidationMessage VARCHAR(500) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    SET @IsValid = 0;
    SET @ValidationMessage = '';

    SELECT @CardId = Id, @AccountId = AccountId, @CardStatus = Status, @CardType = CardType
    FROM Cards.Cards WHERE CardNumber = @CardNumber;

    IF @CardId IS NULL
    BEGIN SET @ValidationMessage = 'Card not found'; RETURN; END;

    IF @CardStatus != 'active'
    BEGIN SET @ValidationMessage = 'Card is ' + @CardStatus; RETURN; END;

    -- Check CVV
    IF NOT EXISTS (SELECT 1 FROM Cards.Cards WHERE Id = @CardId AND CVV = @CVV)
    BEGIN SET @ValidationMessage = 'Invalid CVV'; RETURN; END;

    -- Check expiry
    IF EXISTS (SELECT 1 FROM Cards.Cards WHERE Id = @CardId AND ExpiryDate < GETDATE())
    BEGIN SET @ValidationMessage = 'Card expired'; SET @CardStatus = 'expired'; RETURN; END;

    SET @IsValid = 1;
    SET @ValidationMessage = 'Card validated successfully';

    -- Update last used
    UPDATE Cards.Cards SET LastUsedAt = GETDATE() WHERE Id = @CardId;
    EXEC Audit.sp_LogActivity 'card', @CardId, 'validated';
END;

-- ═══════════════════════════════════════════════════════════
-- SP Level 0: Fraud Check
-- ═══════════════════════════════════════════════════════════

CREATE   PROCEDURE Fraud.sp_CheckFraud
    @AccountId INT,
    @CardId INT,
    @Amount DECIMAL(18,2),
    @MerchantName VARCHAR(200),
    @MerchantCategory VARCHAR(50),
    @TransType VARCHAR(20),
    -- OUTPUT
    @RiskScore INT OUTPUT,
    @IsFlagged BIT OUTPUT,
    @FraudDetails VARCHAR(MAX) OUTPUT,
    @RecommendedAction VARCHAR(50) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    SET @RiskScore = 0;
    SET @IsFlagged = 0;
    SET @FraudDetails = '';
    SET @RecommendedAction = 'approve';

    -- Rule 1: High amount
    IF @Amount > 3000 SET @RiskScore = @RiskScore + 30;
    IF @Amount > 5000 SET @RiskScore = @RiskScore + 20;

    -- Rule 2: Unusual merchant category
    IF @MerchantCategory IN ('gambling', 'crypto', 'adult')
    BEGIN SET @RiskScore = @RiskScore + 40; SET @FraudDetails = @FraudDetails + 'High-risk merchant category. '; END;

    -- Rule 3: Multiple transactions in short time
    DECLARE @RecentCount INT;
    SELECT @RecentCount = COUNT(*) FROM Banking.Transactions 
    WHERE AccountId = @AccountId AND CreatedAt > DATEADD(MINUTE, -5, GETDATE());
    IF @RecentCount > 3
    BEGIN SET @RiskScore = @RiskScore + 25; SET @FraudDetails = @FraudDetails + 'Velocity check: ' + CAST(@RecentCount AS VARCHAR) + ' txns in 5 min. '; END;

    -- Rule 4: First-time merchant
    IF NOT EXISTS (SELECT 1 FROM Banking.Transactions WHERE AccountId = @AccountId AND MerchantName = @MerchantName AND Status = 'approved')
    BEGIN SET @RiskScore = @RiskScore + 10; SET @FraudDetails = @FraudDetails + 'First-time merchant. '; END;

    -- Determine action
    IF @RiskScore >= 80
    BEGIN SET @IsFlagged = 1; SET @RecommendedAction = 'block'; END;
    ELSE IF @RiskScore >= 50
    BEGIN SET @IsFlagged = 1; SET @RecommendedAction = 'review'; END;

    -- Log alert if flagged
    IF @IsFlagged = 1
        EXEC Audit.sp_LogActivity 'fraud', @CardId, 'fraud_alert';
END;

-- ═══ Level 1: Inventory SPs ═══

CREATE   FUNCTION Inventory.fn_CheckStock(@ProductId INT, @Qty INT)
RETURNS BIT AS
BEGIN
    DECLARE @Available INT;
    SELECT @Available = StockQty FROM Inventory.Products WHERE Id = @ProductId;
    RETURN CASE WHEN @Available >= @Qty THEN 1 ELSE 0 END;
END;

CREATE   PROCEDURE Inventory.sp_CheckReorder @ProductId INT
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @Name VARCHAR(255), @SKU VARCHAR(50), @Qty INT, @Threshold INT;
    SELECT @Name = Name, @SKU = SKU, @Qty = StockQty, @Threshold = ReorderLevel
    FROM Inventory.Products WHERE Id = @ProductId;
    IF @Qty <= @Threshold
        EXEC Notifications.sp_SendNotification 'warehouse@company.com', 'low_stock',
            'Low Stock Alert', @Name;
END;

CREATE   PROCEDURE Inventory.sp_ReleaseStock
    @ProductId INT, @Qty INT, @RefType VARCHAR(50), @RefId INT
AS
BEGIN
    SET NOCOUNT ON;
    UPDATE Inventory.Products SET StockQty = StockQty + @Qty WHERE Id = @ProductId;
    INSERT INTO Inventory.StockMovements (ProductId, QtyChange, MoveType, RefId, RefType) VALUES (@ProductId, @Qty, 'return', @RefId, @RefType);
    EXEC Audit.sp_LogActivity 'product', @ProductId, 'stock_released';
END;

CREATE   PROCEDURE Inventory.sp_ReserveStock
    @ProductId INT, @Qty INT, @RefType VARCHAR(50), @RefId INT
AS
BEGIN
    SET NOCOUNT ON;
    IF Inventory.fn_CheckStock(@ProductId, @Qty) = 0
        RAISERROR('Insufficient stock for product %d', 16, 1, @ProductId);

    UPDATE Inventory.Products SET StockQty = StockQty - @Qty WHERE Id = @ProductId;
    INSERT INTO Inventory.StockMovements (ProductId, QtyChange, MoveType, RefId, RefType) VALUES (@ProductId, -@Qty, 'sale', @RefId, @RefType);
    EXEC Audit.sp_LogActivity 'product', @ProductId, 'stock_reserved';
    EXEC Inventory.sp_CheckReorder @ProductId;
END;

CREATE   TRIGGER Inventory.trg_StockLowAlert ON Inventory.Products AFTER UPDATE
AS
BEGIN
    SET NOCOUNT ON;
    IF UPDATE(StockQty)
    BEGIN
        DECLARE @Name VARCHAR(255), @Qty INT, @Threshold INT;
        SELECT @Name = i.Name, @Qty = i.StockQty, @Threshold = i.ReorderLevel FROM inserted i;
        SELECT @Threshold = d.ReorderLevel FROM deleted d WHERE d.StockQty > @Threshold;
        IF @Qty <= @Threshold AND @Threshold IS NOT NULL
            EXEC Notifications.sp_SendNotification 'warehouse@co.com', 'critical_stock', 'Critical Stock', @Name;
    END;
END;

CREATE   PROCEDURE Notifications.sp_SendNotification
    @Email VARCHAR(255), @Type VARCHAR(50), @Subject VARCHAR(255), @Body VARCHAR(MAX)
AS
BEGIN
