END;

-- ═══ Level 2: Order Processing SPs ═══

CREATE   PROCEDURE Orders.sp_CalculateOrderTotals @OrderId INT
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @Subtotal DECIMAL(12,2), @Tax DECIMAL(12,2), @Discount DECIMAL(12,2), @Tier VARCHAR(20);

    SELECT @Subtotal = ISNULL(SUM(LineTotal), 0) FROM Orders.OrderItems WHERE OrderId = @OrderId;
    SET @Tax = @Subtotal * 0.19;

    SELECT @Tier = c.Tier FROM Orders.Customers c JOIN Orders.Orders o ON o.CustomerId = c.Id WHERE o.Id = @OrderId;
    SET @Discount = CASE @Tier WHEN 'vip' THEN @Subtotal * 0.15 WHEN 'premium' THEN @Subtotal * 0.10 ELSE 0 END;

    UPDATE Orders.Orders SET Subtotal = @Subtotal, Tax = @Tax, Discount = @Discount, Total = @Subtotal + @Tax - @Discount WHERE Id = @OrderId;
END;

CREATE   PROCEDURE Orders.sp_CancelOrder @OrderId INT, @Reason VARCHAR(500) = NULL
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @Status VARCHAR(20), @CustomerId INT, @Email VARCHAR(255), @Total DECIMAL(12,2);

    SELECT @Status = Status, @CustomerId = CustomerId, @Total = Total FROM Orders.Orders WHERE Id = @OrderId;
    IF @Status IN ('delivered', 'cancelled') RAISERROR('Cannot cancel order %d', 16, 1, @OrderId);

    BEGIN TRY
        BEGIN TRANSACTION;

        -- Release stock if confirmed
        IF @Status IN ('confirmed', 'paid')
        BEGIN
            DECLARE @ProdId INT, @Qty INT;
            DECLARE cancel_cursor CURSOR FOR SELECT ProductId, Qty FROM Orders.OrderItems WHERE OrderId = @OrderId;
            OPEN cancel_cursor;
            FETCH NEXT FROM cancel_cursor INTO @ProdId, @Qty;
            WHILE @@FETCH_STATUS = 0
            BEGIN
                EXEC Inventory.sp_ReleaseStock @ProdId, @Qty, 'order_cancel', @OrderId;
                FETCH NEXT FROM cancel_cursor INTO @ProdId, @Qty;
            END;
            CLOSE cancel_cursor; DEALLOCATE cancel_cursor;
        END;

        -- Process refund if paid
        IF @Status = 'paid'
            EXEC Payments.sp_ProcessRefund @OrderId, @Total, @Reason;

        UPDATE Orders.Orders SET Status = 'cancelled' WHERE Id = @OrderId;

        SELECT @Email = Email FROM Orders.Customers WHERE Id = @CustomerId;
        EXEC Notifications.sp_SendNotification @Email, 'order_cancelled', 'Order Cancelled', @Reason;
        EXEC Audit.sp_LogActivity 'order', @OrderId, 'cancelled';

        COMMIT TRANSACTION;
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;
        EXEC Audit.sp_LogActivity 'order', @OrderId, 'cancel_failed';
        THROW;
    END CATCH
END;

CREATE   PROCEDURE Orders.sp_CheckTierUpgrade @CustomerId INT
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @TotalSpent DECIMAL(12,2), @CurrentTier VARCHAR(20), @NewTier VARCHAR(20), @Email VARCHAR(255);

    SELECT @TotalSpent = TotalSpent, @CurrentTier = Tier, @Email = Email FROM Orders.Customers WHERE Id = @CustomerId;
    SET @NewTier = CASE WHEN @TotalSpent >= 10000 THEN 'vip' WHEN @TotalSpent >= 1000 THEN 'premium' ELSE 'standard' END;

    IF @NewTier != @CurrentTier
    BEGIN
        UPDATE Orders.Customers SET Tier = @NewTier WHERE Id = @CustomerId;
        EXEC Notifications.sp_SendNotification @Email, 'tier_upgrade', 'Tier Upgraded', @NewTier;
        EXEC Audit.sp_LogActivity 'customer', @CustomerId, 'tier_upgrade';
    END;
END;

CREATE   PROCEDURE Orders.sp_ConfirmOrder @OrderId INT
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @Status VARCHAR(20), @CustomerId INT, @Email VARCHAR(255);

    SELECT @Status = Status, @CustomerId = CustomerId FROM Orders.Orders WHERE Id = @OrderId;
    IF @Status != 'pending' RAISERROR('Order %d is not pending', 16, 1, @OrderId);

    -- Reserve stock for all items
    DECLARE @ProdId INT, @Qty INT;
    DECLARE item_cursor CURSOR FOR SELECT ProductId, Qty FROM Orders.OrderItems WHERE OrderId = @OrderId;
    OPEN item_cursor;
    FETCH NEXT FROM item_cursor INTO @ProdId, @Qty;
    WHILE @@FETCH_STATUS = 0
    BEGIN
        EXEC Inventory.sp_ReserveStock @ProdId, @Qty, 'order', @OrderId;
        FETCH NEXT FROM item_cursor INTO @ProdId, @Qty;
    END;
    CLOSE item_cursor; DEALLOCATE item_cursor;

    EXEC Orders.sp_CalculateOrderTotals @OrderId;
    UPDATE Orders.Orders SET Status = 'confirmed' WHERE Id = @OrderId;

    SELECT @Email = Email FROM Orders.Customers WHERE Id = @CustomerId;
    EXEC Notifications.sp_SendNotification @Email, 'order_confirmed', 'Order Confirmed', 'Your order has been confirmed.';
    EXEC Audit.sp_LogActivity 'order', @OrderId, 'confirmed';
END;

