-- ═══ Level 2: Payment SPs ═══

CREATE   PROCEDURE Payments.sp_ProcessPayment
    @OrderId INT, @Method VARCHAR(50), @TransactionRef VARCHAR(100),
    @PaymentId INT OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @Total DECIMAL(12,2), @CustomerId INT, @Email VARCHAR(255);

    SELECT @Total = Total, @CustomerId = CustomerId FROM Orders.Orders WHERE Id = @OrderId;
    IF @Total IS NULL RAISERROR('Order %d not found', 16, 1, @OrderId);

    INSERT INTO Payments.Payments (OrderId, Amount, Method, Status, TransactionRef, ProcessedAt)
    VALUES (@OrderId, @Total, @Method, 'completed', @TransactionRef, GETDATE());
    SET @PaymentId = SCOPE_IDENTITY();

    UPDATE Orders.Orders SET Status = 'paid' WHERE Id = @OrderId;
    UPDATE Orders.Customers SET TotalSpent = TotalSpent + @Total WHERE Id = @CustomerId;

    EXEC Orders.sp_CheckTierUpgrade @CustomerId;

    SELECT @Email = Email FROM Orders.Customers WHERE Id = @CustomerId;
    EXEC Notifications.sp_SendNotification @Email, 'payment_received', 'Payment Received', @Method;
    EXEC Audit.sp_LogActivity 'payment', @PaymentId, 'processed';
END;

CREATE   PROCEDURE Payments.sp_ProcessRefund @OrderId INT, @Amount DECIMAL(12,2), @Reason VARCHAR(500)
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @PaymentId INT, @RefundId INT;

    SELECT TOP 1 @PaymentId = Id FROM Payments.Payments WHERE OrderId = @OrderId AND Status = 'completed';
    IF @PaymentId IS NULL RAISERROR('No payment found for order %d', 16, 1, @OrderId);

    INSERT INTO Payments.Refunds (PaymentId, Amount, Reason, Status) VALUES (@PaymentId, @Amount, @Reason, 'approved');
    SET @RefundId = SCOPE_IDENTITY();

    UPDATE Payments.Payments SET Status = 'refunded' WHERE Id = @PaymentId;
    EXEC Audit.sp_LogActivity 'refund', @RefundId, 'processed';
END;

-- ═══ Level 3: Report SP (reads across all schemas) ═══

CREATE   PROCEDURE Reports.sp_GenerateDailyReport @ReportDate DATE = NULL
AS
BEGIN
    SET NOCOUNT ON;
    IF @ReportDate IS NULL SET @ReportDate = CAST(GETDATE() AS DATE);

    DECLARE @Orders INT, @Revenue DECIMAL(12,2), @RefundTotal DECIMAL(12,2);

    SELECT @Orders = COUNT(*), @Revenue = ISNULL(SUM(Total), 0) FROM Orders.Orders WHERE CAST(CreatedAt AS DATE) = @ReportDate AND Status != 'cancelled';
    SELECT @RefundTotal = ISNULL(SUM(r.Amount), 0) FROM Payments.Refunds r JOIN Payments.Payments p ON r.PaymentId = p.Id;

    MERGE Reports.DailySales AS target
    USING (SELECT @ReportDate AS ReportDate) AS source ON target.ReportDate = source.ReportDate
    WHEN MATCHED THEN UPDATE SET TotalOrders = @Orders, Revenue = @Revenue, Refunds = @RefundTotal
    WHEN NOT MATCHED THEN INSERT (ReportDate, TotalOrders, Revenue, Refunds) VALUES (@ReportDate, @Orders, @Revenue, @RefundTotal);

    EXEC Audit.sp_LogActivity 'report', NULL, 'daily_report_generated';
END;

-- ═══════════════════════════════════════════════════════════
-- SP: Settlement Queue
-- ═══════════════════════════════════════════════════════════

CREATE   PROCEDURE Settlement.sp_QueueSettlement
    @TransactionId INT,
    @Amount DECIMAL(18,2),
    @MerchantCategory VARCHAR(50)
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @Fee DECIMAL(18,2), @BatchRef VARCHAR(50);

    -- Calculate fee based on merchant category
    SET @Fee = CASE @MerchantCategory 
        WHEN 'retail' THEN @Amount * 0.015
        WHEN 'online' THEN @Amount * 0.025
        WHEN 'travel' THEN @Amount * 0.020
        ELSE @Amount * 0.018
    END;

    SET @BatchRef = 'BATCH-' + CONVERT(VARCHAR, GETDATE(), 112) + '-' + CAST(ABS(CHECKSUM(NEWID())) % 9999 AS VARCHAR);

    INSERT INTO Settlement.SettlementBatch (TransactionId, Amount, Fee, NetAmount, BatchRef)
    VALUES (@TransactionId, @Amount, @Fee, @Amount - @Fee, @BatchRef);

    EXEC Audit.sp_LogActivity 'settlement', @TransactionId, 'queued';
END;
